import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

export default function FacultyDashboard() {
  const { user } = useAuth();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/faculty/stats').then(res => { setData(res.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data) return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load</div></div>;

  const { stats } = data;
  const chartData = [
    { name: 'Submitted', value: stats.submittedMarks, fill: '#1a56db' },
    { name: 'Pending', value: stats.pendingMarks, fill: '#f59e0b' },
    { name: 'Approved', value: stats.approvedMarks, fill: '#10b981' },
    { name: 'Rejected', value: stats.rejectedMarks, fill: '#ef4444' },
  ];

  return (
    <div>
      <div className="info-box" style={{ marginBottom: 20 }}>
        👩‍🏫 Welcome, <strong>{user?.name}</strong> | Dept: <strong>{user?.department?.name}</strong>
      </div>

      <div className="stats-grid">
        <div className="stat-card blue"><div className="stat-icon">📊</div><div><div className="stat-value">{stats.submittedMarks}</div><div className="stat-label">Total Marks Entered</div></div></div>
        <div className="stat-card yellow"><div className="stat-icon">⏳</div><div><div className="stat-value">{stats.pendingMarks}</div><div className="stat-label">Pending Approval</div></div></div>
        <div className="stat-card green"><div className="stat-icon">✅</div><div><div className="stat-value">{stats.approvedMarks}</div><div className="stat-label">Approved</div></div></div>
        <div className="stat-card red"><div className="stat-icon">❌</div><div><div className="stat-value">{stats.rejectedMarks}</div><div className="stat-label">Rejected</div></div></div>
        <div className="stat-card cyan"><div className="stat-icon">📚</div><div><div className="stat-value">{stats.subjectCount}</div><div className="stat-label">Dept Subjects</div></div></div>
      </div>

      <div className="card">
        <div className="card-header"><span className="card-title">Marks Submission Summary</span></div>
        <div className="card-body">
          <div className="chart-container">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <XAxis dataKey="name" /><YAxis allowDecimals={false} /><Tooltip />
                <Bar dataKey="value" radius={[4,4,0,0]}>
                  {chartData.map((entry, i) => (
                    <rect key={i} fill={entry.fill} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
}
